#include <bits/stdc++.h>
#define int long long
using namespace std;
int a[500005] , c[500005] , n , m;
//求x的第1个二进制1的出现位置的2^k
int lowbit( int x ) {
	return x & ( -x );
}
void update( int i , int k ) {
	for( ; i <= n ; i += lowbit( i ) ) {
		c[i] = ( c[i] + k + 2 ) % 2;
	}
}
int getsum( int i ) {
	int ans = 0;
	for( ; i > 0 ; i -= lowbit( i ) ) {
		ans = ( ans + c[i] ) % 2;
	}
	return ans;
}
signed main() {
	cin >> n >> m;
	for( int i = 1 , opt ; i <= m ; i++ ) {
		cin >> opt;
		if( opt == 1 ) {
			int x , y , k = 1;
			cin >> x >> y;
			update( x , k );
			update( y + 1 , -k );
		} else {
			int x;
			cin >> x;
			cout << getsum( x ) << '\n';
		}
	}
	return 0;
}
